const Base64Tool = () => {
  const [mode, setMode] = React.useState('encode');
  const [input, setInput] = React.useState('');
  const [output, setOutput] = React.useState('');
  const [error, setError] = React.useState('');

  const process = () => {
    setError('');
    if (!input) { setOutput(''); return; }
    try {
      if (mode === 'encode') {
        setOutput(btoa(input));
      } else {
        setOutput(atob(input));
      }
    } catch (e) {
      setError(mode === 'encode' ? 'Encoding failed' : 'Invalid base64 input');
      setOutput('');
    }
  };

  React.useEffect(() => {
    process();
  }, [input, mode]);

  const copy = () => {
    if (output) navigator.clipboard.writeText(output);
  };

  const clear = () => {
    setInput('');
    setOutput('');
    setError('');
  };

  return React.createElement('div', { style: { fontFamily: 'system-ui, sans-serif', padding: '16px', display: 'flex', flexDirection: 'column', gap: '14px', height: '100%', overflow: 'auto' } },
    React.createElement('h3', { style: { margin: 0, fontSize: '16px', fontWeight: 600, color: '#111827' } }, 'Base64 Tool'),
    React.createElement('div', { style: { display: 'flex', gap: '8px' } },
      React.createElement('button', {
        onClick: () => setMode('encode'),
        style: {
          flex: 1,
          fontSize: '12px',
          padding: '6px',
          borderRadius: '4px',
          border: '1px solid #d1d5db',
          background: mode === 'encode' ? '#2563eb' : '#fff',
          color: mode === 'encode' ? '#fff' : '#374151',
          cursor: 'pointer',
          fontWeight: 600
        }
      }, 'Encode'),
      React.createElement('button', {
        onClick: () => setMode('decode'),
        style: {
          flex: 1,
          fontSize: '12px',
          padding: '6px',
          borderRadius: '4px',
          border: '1px solid #d1d5db',
          background: mode === 'decode' ? '#2563eb' : '#fff',
          color: mode === 'decode' ? '#fff' : '#374151',
          cursor: 'pointer',
          fontWeight: 600
        }
      }, 'Decode')
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280', marginBottom: '4px' } }, mode === 'encode' ? 'Text to encode' : 'Base64 to decode'),
      React.createElement('textarea', {
        value: input,
        onChange: e => setInput(e.target.value),
        placeholder: mode === 'encode' ? 'Enter text...' : 'Enter base64...',
        style: { width: '100%', minHeight: '100px', fontSize: '13px', padding: '10px', borderRadius: '6px', border: '1px solid #d1d5db', resize: 'vertical', fontFamily: 'monospace', boxSizing: 'border-box' }
      })
    ),
    React.createElement('div', null,
      React.createElement('div', { style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '4px' } },
        React.createElement('span', { style: { fontSize: '11px', fontWeight: 600, color: '#6b7280' } }, mode === 'encode' ? 'Base64 output' : 'Decoded text'),
        React.createElement('div', { style: { display: 'flex', gap: '6px' } },
          React.createElement('button', { onClick: copy, style: { fontSize: '11px', padding: '4px 8px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer' } }, 'Copy'),
          React.createElement('button', { onClick: clear, style: { fontSize: '11px', padding: '4px 8px', borderRadius: '4px', border: '1px solid #d1d5db', background: '#fff', cursor: 'pointer' } }, 'Clear')
        )
      ),
      React.createElement('div', {
        style: {
          width: '100%',
          minHeight: '100px',
          fontSize: '13px',
          padding: '10px',
          borderRadius: '6px',
          border: '1px solid ' + (error ? '#fca5a5' : '#d1d5db'),
          background: error ? '#fef2f2' : '#f9fafb',
          fontFamily: 'monospace',
          wordBreak: 'break-all',
          color: error ? '#dc2626' : '#111827',
          boxSizing: 'border-box'
        }
      }, error || output || 'Result will appear here...')
    )
  );
};
render(<Base64Tool/>);
